#endif
#ifndef WRAP_FMA_NS
#define WRAP_FMA_NS 0.40  /* ns per FMA in wrap correction (memory-latency-bound) */
#endif
#ifndef PAIRED_CACHED_CORR_RATIO
#define PAIRED_CACHED_CORR_RATIO 1.8287  /* paired cached correlate / full pipeline */
#endif
